1	// claim-office.spec.ts
2	//
3	// Test list for the MHPCO Claim Office kata (see prompt.md).
4	// Core logic is tested through the exported processScenario function,
5	// which takes a scenario ({ customer, steps }) and returns { results }.
6	// CLI behavior (stdin/stdout/exit codes) is tested by running src/cli.ts
7	// (e.g. via tsx with execFile from node:child_process).
8	//
9	// Unless stated otherwise, quote scenarios assume a newcomer
10	// (yearsWithMHPCO: 0) and the customer's first quote in the scenario,
11	// so every quoted premium includes the 10 % first-insurance surcharge
12	// (computed on the policy base premium) and the 5 G processing fee.
13	import { describe, it, expect } from "vitest";
14	import { processScenario } from "./claim-office.js";
15	
16	describe("MHPCO Claim Office", () => {
17	  describe("Quote: base premiums", () => {
18	    it("should quote 5 G for an empty item list (only the processing fee)", () => {
19	      const { results } = processScenario({
20	        customer: { yearsWithMHPCO: 0 },
21	        steps: [{ op: "quote", items: [] }],
22	      });
23	
24	      expect(results[0].premium).toBe(5);
25	    });
26	    it.todo("should quote 115 G for a single plain sword (base 100 + 10 first insurance + 5 fee)");
27	    it.todo("should quote 71 G for a single plain amulet (base 60 + 6 + 5)");
28	    it.todo("should quote 93 G for a single plain staff (base 80 + 8 + 5)");
29	    it.todo("should quote 49 G for a single plain potion (base 40 + 4 + 5)");
30	  });
31	
32	  describe("Quote: component blocks", () => {
33	    it.todo("should quote 60 G for 2 runes (base 50, no block)");
34	    it.todo("should quote 71 G for 3 runes (block base 60 instead of 75)");
35	    it.todo("should quote 115 G for 4 runes (base 100 — block requires exactly 3)");
36	    it.todo("should quote 198 G for 7 runes (base 175, total 197.5 rounded up)");
37	    it.todo("should quote 88 G for 2 runes + 1 moonstone (base 75 — no block across different types)");
38	    it.todo("should quote 137 G for 3 runes + 3 moonstones (base 120 — two separate blocks)");
39	  });
40	
41	  describe("Quote: premium modifiers", () => {
42	    it.todo("should apply the curse surcharge only to the cursed item's base premium: cursed sword + plain amulet quotes 231 G (base 160 + 50 curse + 16 first insurance + 5 fee)");
43	    it.todo("should apply the 20 % loyalty discount at exactly 2 years: plain sword quotes 95 G (100 - 20 + 10 + 5)");
44	    it.todo("should apply the high-enchantment surcharge at exactly enchantment 5: sword quotes 145 G (100 + 30 + 10 + 5)");
45	    it.todo("should stack curse and high-enchantment surcharges: cursed sword with enchantment 5 quotes 195 G (100 + 30 + 50 + 10 + 5)");
46	    it.todo("should not apply the high-enchantment surcharge at enchantment 4: plain sword quotes 115 G");
47	    it.todo("should apply only the curse surcharge to a cursed sword with enchantment 4: quotes 165 G");
48	  });
49	
50	  describe("Quote: integration examples", () => {
51	    it.todo("should quote 165 G for a newcomer with a cursed steel sword, enchantment 3 (100 + 50 curse + 10 first insurance = 160 + 5 fee)");
52	    it.todo("should quote 160 G for a 3-year customer's second quote with a cursed steel sword, enchantment 7 (100 + 50 + 30 - 20 loyalty + 10 first insurance - 15 follow-up = 155 + 5 fee)");
53	  });
54	
55	  describe("Claim: standard reimbursement", () => {
56	    it.todo("should pay 400 G for 500 G damage to a regular steel sword, enchantment 3 (full reimbursement minus 100 G deductible), remainingCap 1600 G");
57	    it.todo("should pay 100 G for 200 G damage to a rune (no special clause applies), remainingCap 400 G");
58	  });
59	
60	  describe("Claim: special clauses", () => {
61	    it.todo("should pay 400 G for 1000 G damage to a dragon-material sword with exactly enchantment 8 (50 % clause, then deductible)");
62	    it.todo("should pay 400 G for 1000 G damage to a dragon-material sword with enchantment 9 (both clauses apply, the 50 % rule wins: 500 - 100)");
63	    it.todo("should pay 700 G for 800 G damage to a dragon-material sword with enchantment 5 (full reimbursement, then deductible: 800 - 100)");
64	    it.todo("should pay 400 G for 1000 G damage to a steel sword with enchantment 9 (50 % first, then deductible: 500 - 100)");
65	  });
66	
67	  describe("Claim: deductible per damage entry", () => {
68	    it.todo("should apply the 100 G deductible once per damaged item: sword damaged 500 G and amulet damaged 300 G pays 600 G, remainingCap 2600 G");
69	  });
70	
71	  describe("Claim: multiple items of the same type", () => {
72	    it.todo("should treat each damage entry as a separate damage with its own deductible: policy with two swords (cap 4000 G), two sword damages of 500 G each pay 800 G, remainingCap 3200 G");
73	  });
74	
75	  describe("Claim: payout cap", () => {
76	    it.todo("should cap the first of two 1500 G claims on a single insured sword at full reimbursement: payout 1400 G, remainingCap 600 G");
77	    it.todo("should reduce the second 1500 G claim to the remaining cap: payout 600 G, remainingCap 0 G");
78	    it.todo("should base the cap on the unmodified insurance value: cursed sword (cap 2000 G), 2500 G damage pays 2000 G, remainingCap 0 G");
79	    it.todo("should exclude the block discount from the insurance sum: sword + 3 runes (cap 3500 G), 4000 G sword damage pays 3500 G, remainingCap 0 G");
80	  });
81	
82	  describe("Rounding in the MHPCO's favor", () => {
83	    it.todo("should round the final premium up: a quote yielding 197.5 G results in 198 G");
84	    it.todo("should round the final payout down: 901 G damage to a steel sword with enchantment 9 yields 350.5 G and pays 350 G");
85	  });
86	
87	  describe("CLI", () => {
88	    it.todo("should read a scenario from stdin and write results to stdout: schema example (5 years, amulet quote then 200 G fire damage) outputs premium 59, payout 100, remainingCap 1100 and exits with code 0");
89	    it.todo("should exit non-zero with an error on stderr and no results on stdout for a quote with an unknown item type (broomstick)");
90	    it.todo("should exit non-zero with an error on stderr for a claim damaging an item not in the policy (amulet damaged, only sword insured)");
91	    it.todo("should exit non-zero with an error on stderr for a claim with a damage entry of unknown item type");
92	    it.todo("should exit non-zero with an error on stderr when damages contain more entries of a type than the policy covers (two sword damages, one sword insured)");
93	    it.todo("should exit non-zero with an error on stderr for a damage entry with a negative amount (-200)");
94	  });
95	});
96

1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type QuoteStep = {
6	  op: "quote";
7	  items: unknown[];
8	};
9	
10	export type Step = QuoteStep;
11	
12	export type Scenario = {
13	  customer: Customer;
14	  steps: Step[];
15	};
16	
17	export type QuoteResult = {
18	  premium: number;
19	};
20	
21	export type Result = QuoteResult;
22	
23	export const processScenario = (scenario: Scenario): { results: Result[] } => {
24	  return { results: [{ premium: 0 }] };
25	};
